\expandafter\def\expandafter\e1unit\expandafter{\expandafter\hat\expandafter{\e1}}

\begin{tikzpicture}
    \node[htaucell] at (1, 0) {$\e1unit$}; % Should now show \hat{\mathbf{\tau}}
